@namespace Lumeo

@{
    var context = new AccordionContext(Type, _openItems, EventCallback.Factory.Create<string>(this, ToggleItem));
}

<div class="@CssClass" @attributes="AdditionalAttributes">
    <CascadingValue Value="context" IsFixed="false">
        @ChildContent
    </CascadingValue>
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public AccordionType Type { get; set; } = AccordionType.Single;
    [Parameter] public List<string>? DefaultValues { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly HashSet<string> _openItems = new();
    private bool _initialized;

    private string CssClass => $"{Class}".Trim();

    protected override void OnInitialized()
    {
        if (!_initialized && DefaultValues is { Count: > 0 })
        {
            foreach (var value in DefaultValues)
            {
                _openItems.Add(value);
            }
            _initialized = true;
        }
    }

    private Task ToggleItem(string value)
    {
        if (_openItems.Contains(value))
        {
            _openItems.Remove(value);
        }
        else
        {
            if (Type == AccordionType.Single)
            {
                _openItems.Clear();
            }
            _openItems.Add(value);
        }
        StateHasChanged();
        return Task.CompletedTask;
    }

    public enum AccordionType { Single, Multiple }

    public record AccordionContext(AccordionType Type, HashSet<string> OpenItems, EventCallback<string> Toggle)
    {
        public bool IsOpen(string value) => OpenItems.Contains(value);
    }
}

@namespace Lumeo

@if (ForceMount || IsOpen)
{
    <div class="@CssClass" hidden="@(IsOpen ? null : "hidden")" @attributes="AdditionalAttributes">
        <div class="pb-4 pt-0">
            @ChildContent
        </div>
    </div>
}

@code {
    [CascadingParameter] public Accordion.AccordionContext Context { get; set; } = default!;
    [CascadingParameter] public AccordionItem.AccordionItemContext ItemContext { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>
    /// When true, this panel is always rendered into the DOM (with the
    /// <c>hidden</c> attribute when closed) instead of being unmounted.
    /// Use when child state (form inputs, scroll position, expensive
    /// component init) must survive closing the accordion item.
    /// Default <c>false</c> preserves the original unmount behaviour.
    /// </summary>
    [Parameter] public bool ForceMount { get; set; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool IsOpen => Context.IsOpen(ItemContext.Value);

    private string CssClass => $"overflow-hidden text-sm {(IsOpen ? "animate-accordion-down" : "")} {Class}".Trim();
}

@namespace Lumeo

@{
    var itemContext = new AccordionItemContext(Value, Disabled);
}

<CascadingValue Value="itemContext" IsFixed="false">
    <div class="@CssClass" @attributes="AdditionalAttributes">
        @ChildContent
    </div>
</CascadingValue>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter, EditorRequired] public string Value { get; set; } = "";
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => string.Join(" ", new[] { "border-b border-border/40", Disabled ? "opacity-50" : null, Class }.Where(s => !string.IsNullOrWhiteSpace(s)));

    public record AccordionItemContext(string Value, bool Disabled);
}

@namespace Lumeo

<button type="button" class="@CssClass" aria-expanded="@IsOpen" disabled="@IsDisabled" @onclick="Toggle" @attributes="AdditionalAttributes">
    @ChildContent
    <Blazicon Svg="Lucide.ChevronDown" class="@IconClasses" />
</button>

@code {
    [CascadingParameter] public Accordion.AccordionContext Context { get; set; } = default!;
    [CascadingParameter] public AccordionItem.AccordionItemContext ItemContext { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool IsOpen => Context.IsOpen(ItemContext.Value);
    private bool IsDisabled => ItemContext.Disabled;

    private string CssClass => $"flex flex-1 w-full items-center justify-between py-4 text-sm font-medium transition-all focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 rounded-sm {(IsDisabled ? "cursor-not-allowed" : "cursor-pointer hover:underline")} {Class}".Trim();

    private string IconClasses => string.Join(" ", new[] { "h-4 w-4 shrink-0 text-muted-foreground transition-transform duration-200", IsOpen ? "rotate-180" : null }.Where(s => !string.IsNullOrWhiteSpace(s)));

    private async Task Toggle()
    {
        if (IsDisabled) return;
        await Context.Toggle.InvokeAsync(ItemContext.Value);
    }
}
